select 
from querendingdan q
left join paotuixiangmu p on q.project_id = p.id


        and (q.order_no like concat('%',#{keyword},'%') or q.user_name like concat('%',#{keyword},'%') or q.paotui_name like concat('%',#{keyword},'%'))

    and q.user_id = #{userId}
    and q.paotui_id = #{paotuiId}
    and q.is_pay = #{isPay}

order by q.id desc

